import{_ as e,o as t,c as s,a3 as o}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"生肖 · 鼠","description":"子鼠——机敏聪慧，十二生肖之首","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 鼠","description":"子鼠——机敏聪慧，十二生肖之首"},"headers":[],"relativePath":"changshi/shengxiao/shu.md","filePath":"changshi/shengxiao/shu.md","lastUpdated":1779783531000}'),i={name:"changshi/shengxiao/shu.md"};function n(r,a,h,p,c,l){return t(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="子鼠" tabindex="-1">子鼠 <a class="header-anchor" href="#子鼠" aria-label="Permalink to &quot;子鼠&quot;">​</a></h1><blockquote><p>地支「子」· 子时（23:00–01:00）· 五行属水 · 阴阳为阳</p></blockquote><p>老鼠小巧玲珑，行动敏捷，子时胆量最壮、活动最频繁。在我国古代文化中，老鼠有「子」和「财」的寓意，象征生生不息和福气财运。老鼠繁殖能力极强，古人「鼠戏葡萄」代表儿孙满堂、多子多福；旧时老鼠被称为「仓神」，家里有老鼠证明有余粮，也象征财力丰厚。</p><h2 id="生肖故事-聪明的投机者" tabindex="-1">生肖故事：聪明的投机者 <a class="header-anchor" href="#生肖故事-聪明的投机者" aria-label="Permalink to &quot;生肖故事：聪明的投机者&quot;">​</a></h2><p>传说玉皇大帝想选十二种动物作为守卫轮流值班，下令所有动物在正月初九前来祝寿，按到达先后顺序定生肖排位。</p><p>老鼠和猫本是邻居，弱小的老鼠总受猫欺负。接到玉帝命令，猫让老鼠在祝寿这天叫醒它一同前往。老鼠满口答应，内心却暗自窃喜——报复的机会来了！正月初九早晨，猫一如既往地熟睡，老鼠悄悄出发了。</p><p>到了宽阔的河边，老鼠犯愁无法渡河。看到牛到达，老鼠灵机一动跳到牛背上借力。憨厚的牛乐于助人，不在意老鼠的投机。渡过河后，老鼠觉得躺在牛身上既舒服又省力，就没有跳下来。中午牛载着老鼠到了天宫前，就在牛刚要跨进门时，老鼠迫不及待地蹿出来，抢先跳到玉帝面前——成了第一名。</p><p>正月初十，熟睡了一整天的猫终于醒了。听说老鼠成了第一名，猫认为老鼠顶替了自己，从此恨之入骨，与老鼠结下了深仇——这就是猫捉老鼠的由来。</p>',8)])])}const u=e(i,[["render",n]]);export{_ as __pageData,u as default};
